"""Persistence layer for notification system."""

_channels = {}
_templates = {}
_messages = []
_subscribers = {}


def reset():
    """Reset all storage."""
    global _channels, _templates, _messages, _subscribers
    _channels = {}
    _templates = {}
    _messages = []
    _subscribers = {}


# --- Channel management ---

def add_channel(channel_id, name, channel_type, priority):
    """Add a notification channel."""
    _channels[channel_id] = {
        "id": channel_id,
        "name": name,
        "type": channel_type,
        "priority": priority,
    }


def get_channel(channel_id):
    """Get a channel by ID."""
    return _channels.get(channel_id)


def get_channels_by_priority():
    """Return channels sorted by priority (highest first).
    Priority: high > medium > low.
    """
    # BUG 2: Sorts alphabetically by priority string.
    # Alphabetical: high, low, medium — puts 'low' before 'medium'!
    channels = list(_channels.values())
    channels.sort(key=lambda c: c["priority"])
    return channels


# --- Template management ---

def add_template(template_id, body, subject=None, parent_id=None, defaults=None):
    """Add a notification template."""
    _templates[template_id] = {
        "id": template_id,
        "body": body,
        "subject": subject,
        "parent_id": parent_id,
        "defaults": defaults or {},
    }


def get_template(template_id):
    """Get a template by ID. If it has a parent, should merge parent defaults."""
    tmpl = _templates.get(template_id)
    if tmpl is None:
        return None
    # BUG 5: Returns child template without merging parent defaults.
    # If parent has defaults like {"footer": "Unsubscribe link"},
    # child should inherit those unless it overrides them.
    return tmpl.copy()


# --- Message log ---

def log_message(channel_id, recipient, body, timestamp):
    """Log a sent message."""
    _messages.append({
        "channel_id": channel_id,
        "recipient": recipient,
        "body": body,
        "timestamp": timestamp,
    })


def get_messages_in_window(channel_id, recipient, start_ts, end_ts):
    """Get messages sent to recipient on channel within time window.
    start_ts and end_ts are Unix timestamps (should be compared as numbers).
    """
    # BUG 3: Compares timestamps as strings instead of ints.
    # String comparison: "9" > "10" (because '9' > '1'),
    # so messages at timestamp 9 appear to be after timestamp 10.
    result = []
    for msg in _messages:
        if (msg["channel_id"] == channel_id and
            msg["recipient"] == recipient and
            msg["timestamp"] >= str(start_ts) and
            msg["timestamp"] <= str(end_ts)):
            result.append(msg)
    return result


def get_all_messages():
    """Get all logged messages."""
    return list(_messages)


# --- Subscriber management ---

def add_subscriber(user_id, channel_id):
    """Subscribe a user to a channel."""
    key = (user_id, channel_id)
    _subscribers[key] = {"user_id": user_id, "channel_id": channel_id, "active": True}


def remove_subscriber(user_id, channel_id):
    """Unsubscribe a user from a channel."""
    key = (user_id, channel_id)
    if key in _subscribers:
        _subscribers[key]["active"] = False


def get_active_subscribers(channel_id):
    """Get all active subscribers for a channel."""
    result = []
    for key, sub in _subscribers.items():
        if sub["channel_id"] == channel_id and sub["active"]:
            result.append(sub["user_id"])
    return result


def is_subscribed(user_id, channel_id):
    """Check if user is actively subscribed to channel."""
    key = (user_id, channel_id)
    sub = _subscribers.get(key)
    return sub is not None and sub["active"]

seed_files.controller.py:
"""Request handling layer for notification system."""
import service
import storage

# Simulated config (as if read from file/env — values are strings)
_config = {
    "max_retries": "3",
    "rate_limit_per_hour": "10",
}


def handle_create_channel(channel_id, name, channel_type, priority):
    """Create a notification channel."""
    storage.add_channel(channel_id, name, channel_type, priority)
    return {"status": "ok", "channel_id": channel_id}


def handle_create_template(template_id, body, subject=None, parent_id=None, defaults=None):
    """Create a notification template."""
    storage.add_template(template_id, body, subject, parent_id, defaults)
    return {"status": "ok", "template_id": template_id}


def handle_send_notification(channel_id, recipient, template_id, variables):
    """Send a notification."""
    # BUG 1: Converts ALL variable values to strings, even numeric ones.
    # This means {count:d} format spec fails because 'd' doesn't work on strings.
    str_variables = {k: str(v) for k, v in variables.items()}
    result = service.send_notification(channel_id, recipient, template_id, str_variables)
    return {"status": "ok", "result": result}


def handle_bulk_send(channel_id, template_id, variables):
    """Send notification to all subscribers of a channel."""
    results = service.bulk_send(channel_id, template_id, variables)
    return {"status": "ok", "sent_count": len(results), "results": results}


def handle_subscribe(user_id, channel_id):
    """Subscribe a user to a channel."""
    service.subscribe_user(user_id, channel_id)
    return {"status": "ok"}


def handle_unsubscribe(user_id, channel_id):
    """Unsubscribe a user from a channel."""
    service.unsubscribe_user(user_id, channel_id)
    return {"status": "ok"}


def handle_get_priority_channels():
    """Get channels sorted by priority."""
    channels = service.get_priority_channels()
    return {"status": "ok", "channels": channels}


def handle_check_rate_limit(channel_id, recipient):
    """Check if recipient is within rate limit for channel."""
    limit = int(_config["rate_limit_per_hour"])
    allowed = service.check_rate_limit(channel_id, recipient, limit)
    return {"status": "ok", "allowed": allowed}


def handle_check_retry(retry_count):
    """Check if a delivery should be retried."""
    # BUG 6: Passes max_retries as string from config.
    # service.should_retry compares int < str, which raises TypeError.
    max_retries = _config["max_retries"]
    return {"status": "ok", "should_retry": service.should_retry(retry_count, max_retries)}


def handle_render_template(template_id, variables):
    """Render a template with variables (for preview)."""
    body = service.render_template(template_id, variables)
    return {"status": "ok", "body": body}
